function candidate(input) {
  const value = input || {};
  let output = "";

  const read = (...keys) => {
    for (const key of keys) {
      if (value[key] !== undefined && value[key] !== null && value[key] !== "") {
        return String(value[key]);
      }
    }
    return "";
  };

  const scheme = read("scheme", "protocol");
  const credentials = read("credentials", "auth", "userinfo", "userInfo");
  const location = read("netloc", "networkLocation", "host", "hostname");
  const port = read("port");
  const path = read("path", "pathname");

  if (scheme) output += scheme.endsWith(":") ? scheme : scheme + ":";
  if (value.slashes || value.authorityDelimiter || value.hasAuthority || credentials || location || port) output += "//";
  if (credentials) output += credentials + "@";
  if (location) output += location;
  if (port) output += ":" + String(port).replace(/^:/, "");
  if (path) output += path;

  return output;
}
